1	/** A live cell at coordinates (x, y). */
2	export type Cell = [number, number];
3	
4	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
5	  [-1, -1], [-1, 0], [-1, 1],
6	  [ 0, -1],          [ 0, 1],
7	  [ 1, -1], [ 1, 0], [ 1, 1],
8	];
9	
10	const key = ([x, y]: Cell): string => `${x},${y}`;
11	
12	const neighborsOf = ([x, y]: Cell): Cell[] =>
13	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
14	
15	const uniqueCells = (cells: Cell[]): Cell[] => {
16	  const seen = new Map<string, Cell>();
17	  for (const cell of cells) seen.set(key(cell), cell);
18	  return [...seen.values()];
19	};
20	
21	const livesNextGeneration = (cell: Cell, liveKeys: Set<string>): boolean => {
22	  const liveNeighborCount = neighborsOf(cell).filter((n) => liveKeys.has(key(n))).length;
23	  const isAlive = liveKeys.has(key(cell));
24	  return liveNeighborCount === 3 || (isAlive && liveNeighborCount === 2);
25	};
26	
27	/**
28	 * Computes the next generation of Conway's Game of Life
29	 * from the currently live cells.
30	 */
31	export function nextGeneration(liveCells: Cell[]): Cell[] {
32	  const liveKeys = new Set(liveCells.map(key));
33	  const candidates = uniqueCells([...liveCells, ...liveCells.flatMap(neighborsOf)]);
34	  return candidates.filter((cell) => livesNextGeneration(cell, liveKeys));
35	}
36

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single cell dies from underpopulation — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent cells both die from underpopulation — [(0,1), (1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("block still life stays unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
15	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result).toHaveLength(4);
18	    expect(result).toEqual(expect.arrayContaining(block));
19	  });
20	  it("rule 2 survival: middle of row survives with 2 neighbors — [(0,0),(1,0),(2,0)] includes (1,0)", () => {
21	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
22	    expect(result).toEqual(expect.arrayContaining([[1, 0]]));
23	  });
24	  it("rule 3 overpopulation: center of plus-shape with 4 neighbors dies", () => {
25	    const plus: Cell[] = [[1, 0], [0, 1], [1, 1], [2, 1], [1, 2]];
26	    const result = nextGeneration(plus);
27	    expect(result).not.toEqual(expect.arrayContaining([[1, 1]]));
28	  });
29	  it("rule 4 reproduction: L-shape becomes block — [(0,0),(1,0),(0,1)] → adds (1,1)", () => {
30	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
31	    expect(result).toEqual(expect.arrayContaining([[1, 1]]));
32	  });
33	  it("blinker oscillates vertical → horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
34	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
35	    expect(result).toHaveLength(3);
36	    expect(result).toEqual(expect.arrayContaining<Cell>([[-1, 1], [0, 1], [1, 1]]));
37	  });
38	  it("handles negative coordinates — blinker at (-5,-5) rotates", () => {
39	    const result = nextGeneration([[-5, -6], [-5, -5], [-5, -4]]);
40	    expect(result).toHaveLength(3);
41	    expect(result).toEqual(
42	      expect.arrayContaining<Cell>([[-6, -5], [-5, -5], [-4, -5]]),
43	    );
44	  });
45	});
